import{_ as l,o as e,c as i,a2 as t}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"基本原理","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/how-it-works.md","filePath":"concepts/how-it-works.md","lastUpdated":null}'),o={name:"concepts/how-it-works.md"};function r(n,a,s,d,h,p){return e(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="基本原理" tabindex="-1">基本原理 <a class="header-anchor" href="#基本原理" aria-label="Permalink to &quot;基本原理&quot;">​</a></h1><p>一句话：多数 AI 绘画模型不是直接“一笔画出图片”，而是在噪声中一步步去噪，逐渐形成符合提示词的图像。</p><h2 id="从噪声到图片" tabindex="-1">从噪声到图片 <a class="header-anchor" href="#从噪声到图片" aria-label="Permalink to &quot;从噪声到图片&quot;">​</a></h2><p>扩散模型的直观过程：</p><ol><li>从一张随机噪声开始。</li><li>文本编码器把提示词变成条件信息。</li><li>模型根据条件预测“应该去掉哪些噪声”。</li><li>采样器重复执行多步去噪。</li><li>VAE 把内部 latent 结果解码成图片。</li></ol><p>所以，同一个提示词换一个随机种子，也可能得到完全不同的图。</p><h2 id="latent-space-是什么" tabindex="-1">Latent Space 是什么 <a class="header-anchor" href="#latent-space-是什么" aria-label="Permalink to &quot;Latent Space 是什么&quot;">​</a></h2><p>Latent space 可以理解为模型内部的压缩空间。模型不是直接在最终像素上工作，而是在更小、更抽象的表示里操作。</p><p>好处是：</p><ul><li>速度更快。</li><li>显存压力更低。</li><li>模型更容易学习图像结构。</li></ul><p>最后再通过 VAE 解码成普通图片。</p><h2 id="采样步数" tabindex="-1">采样步数 <a class="header-anchor" href="#采样步数" aria-label="Permalink to &quot;采样步数&quot;">​</a></h2><p>采样步数是去噪迭代次数。</p><ul><li>步数太少：画面可能粗糙、不完整。</li><li>步数适中：质量和速度平衡。</li><li>步数太多：不一定更好，可能只是更慢。</li></ul><p>不同模型推荐步数不同。Turbo 类模型往往步数更少，普通模型可能需要更多步。</p><h2 id="cfg-是什么" tabindex="-1">CFG 是什么 <a class="header-anchor" href="#cfg-是什么" aria-label="Permalink to &quot;CFG 是什么&quot;">​</a></h2><p>CFG 可以理解为“模型听提示词的强度”。</p><ul><li>CFG 太低：模型更自由，但可能不跟提示词。</li><li>CFG 适中：提示词和画面自然度平衡。</li><li>CFG 太高：可能过度锐化、颜色异常、结构变差。</li></ul><p>不同模型对 CFG 敏感程度不同。新模型不一定需要很高 CFG。</p><h2 id="seed-是什么" tabindex="-1">Seed 是什么 <a class="header-anchor" href="#seed-是什么" aria-label="Permalink to &quot;Seed 是什么&quot;">​</a></h2><p>Seed 是随机种子。它决定初始噪声。</p><ul><li>固定 seed：方便复现实验，比较参数变化。</li><li>随机 seed：适合探索新结果。</li></ul><p>如果你想判断某个参数有没有效果，应该固定 seed 再改一个变量。</p><h2 id="为什么模型不完全听话" tabindex="-1">为什么模型不完全听话 <a class="header-anchor" href="#为什么模型不完全听话" aria-label="Permalink to &quot;为什么模型不完全听话&quot;">​</a></h2><p>AI 绘画不是严格执行程序，而是在概率空间里生成最可能的图像。它可能不听话的原因包括：</p><ul><li>底模没有学好这个概念。</li><li>提示词互相冲突。</li><li>LoRA 权重太高或不兼容。</li><li>图片尺寸不适合模型。</li><li>采样参数过激。</li><li>训练数据里相关概念本来就混乱。</li></ul><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><ul><li>“步数越高越好”：不一定，超过推荐范围收益可能很低。</li><li>“CFG 越高越听话”：过高会损害画面。</li><li>“同一提示词应该出同一张图”：除非固定 seed 和全部参数。</li><li>“提示词能精确控制一切”：复杂姿势、构图和局部结构通常需要 ControlNet、参考图或后期编辑。</li></ul>',28)])])}const _=l(o,[["render",r]]);export{u as __pageData,_ as default};
